-- =============================================
-- SEED DATA — Exécuter APRÈS schema.sql
-- Cash = TOUJOURS en EUR (même CTO)
-- FX Rate = USDEUR (combien d'EUR pour 1 USD)
-- =============================================

ON CONFLICT (name) DO NOTHING;

ON CONFLICT (person_id, type) DO UPDATE SET
  total_invested = EXCLUDED.total_invested,
  cash = EXCLUDED.cash;

ON CONFLICT (account_id, ticker) DO UPDATE SET shares = EXCLUDED.shares, label = EXCLUDED.label;

ON CONFLICT (account_id, ticker) DO UPDATE SET shares = EXCLUDED.shares;

ON CONFLICT (account_id, date) DO UPDATE SET portfolio_value=EXCLUDED.portfolio_value, index_value=EXCLUDED.index_value, cash=EXCLUDED.cash, fx_rate=EXCLUDED.fx_rate, confirmed=true;

ON CONFLICT (account_id, date) DO UPDATE SET portfolio_value=EXCLUDED.portfolio_value, index_value=EXCLUDED.index_value, cash=EXCLUDED.cash, fx_rate=EXCLUDED.fx_rate, confirmed=true;

